import { defineType, defineField } from 'sanity';

export const homePage = defineType({
  name: 'homePage',
  title: 'Home Page',
  type: 'document',
  fields: [
    // ── Hero ──────────────────────────────────────────────────────────
    defineField({
      name: 'heroImage',
      title: 'Hero Image',
      type: 'image',
      options: { hotspot: true },
    }),
    defineField({
      name: 'heroTitle',
      title: 'Hero Title',
      type: 'string',
      validation: (rule) => rule.required(),
    }),
    defineField({
      name: 'heroSubtitle',
      title: 'Hero Subtitle',
      type: 'string',
    }),
    defineField({
      name: 'heroCtaText',
      title: 'Hero CTA Text',
      type: 'string',
    }),
    defineField({
      name: 'heroCtaHref',
      title: 'Hero CTA Link',
      type: 'string',
    }),

    // ── Service Times ────────────────────────────────────────────────
    defineField({
      name: 'serviceTimes',
      title: 'Service Times',
      type: 'array',
      of: [
        {
          type: 'object',
          name: 'serviceTime',
          title: 'Service Time',
          fields: [
            defineField({
              name: 'label',
              title: 'Label',
              type: 'string',
              validation: (rule) => rule.required(),
            }),
            defineField({
              name: 'time',
              title: 'Time',
              type: 'string',
              validation: (rule) => rule.required(),
            }),
          ],
          preview: {
            select: { title: 'label', subtitle: 'time' },
          },
        },
      ],
    }),

    // ── Photo Mosaic ─────────────────────────────────────────────────
    defineField({
      name: 'mosaicImages',
      title: 'Mosaic Images',
      type: 'array',
      of: [
        {
          type: 'image',
          options: { hotspot: true },
          fields: [
            defineField({
              name: 'alt',
              title: 'Alt Text',
              type: 'string',
            }),
          ],
        },
      ],
    }),

    // ── Pillars ──────────────────────────────────────────────────────
    defineField({
      name: 'pillars',
      title: 'Pillars',
      type: 'array',
      of: [
        {
          type: 'object',
          name: 'pillar',
          title: 'Pillar',
          fields: [
            defineField({
              name: 'title',
              title: 'Title',
              type: 'string',
              validation: (rule) => rule.required(),
            }),
            defineField({
              name: 'description',
              title: 'Description',
              type: 'text',
            }),
          ],
          preview: {
            select: { title: 'title' },
          },
        },
      ],
    }),

    // ── Next Steps ───────────────────────────────────────────────────
    defineField({
      name: 'nextSteps',
      title: 'Next Steps',
      type: 'array',
      of: [
        {
          type: 'object',
          name: 'nextStep',
          title: 'Next Step',
          fields: [
            defineField({
              name: 'title',
              title: 'Title',
              type: 'string',
              validation: (rule) => rule.required(),
            }),
            defineField({
              name: 'body',
              title: 'Body',
              type: 'string',
            }),
            defineField({
              name: 'href',
              title: 'Link',
              type: 'string',
            }),
            defineField({
              name: 'image',
              title: 'Image',
              type: 'image',
              options: { hotspot: true },
            }),
          ],
          preview: {
            select: { title: 'title', subtitle: 'href' },
          },
        },
      ],
    }),

    // ── Language ──────────────────────────────────────────────────────
    defineField({
      name: 'language',
      title: 'Language',
      type: 'string',
      options: { list: ['en', 'zh'] },
      initialValue: 'en',
      validation: (rule) => rule.required(),
    }),
  ],
  preview: {
    select: { language: 'language' },
    prepare: ({ language }) => ({
      title: 'Home Page',
      subtitle: language?.toUpperCase(),
    }),
  },
});

// Object / block types
export { heroBlock } from './objects/heroBlock';
export { imageMosaicBlock } from './objects/imageMosaicBlock';
export { accordionBlock } from './objects/accordionBlock';
export { cardGridBlock } from './objects/cardGridBlock';
export { youtubeEmbedBlock } from './objects/youtubeEmbedBlock';

// Document types
export { person } from './documents/person';
export { sermon } from './documents/sermon';
export { event } from './documents/event';
export { ministry } from './documents/ministry';
export { page } from './documents/page';

// Singletons
export { siteSettings } from './singletons/siteSettings';
export { navigation } from './singletons/navigation';
export { homePage } from './singletons/homePage';
export { aboutPage } from './singletons/aboutPage';

import { heroBlock } from './objects/heroBlock';
import { imageMosaicBlock } from './objects/imageMosaicBlock';
import { accordionBlock } from './objects/accordionBlock';
import { cardGridBlock } from './objects/cardGridBlock';
import { youtubeEmbedBlock } from './objects/youtubeEmbedBlock';
import { person } from './documents/person';
import { sermon } from './documents/sermon';
import { event } from './documents/event';
import { ministry } from './documents/ministry';
import { page } from './documents/page';
import { siteSettings } from './singletons/siteSettings';
import { navigation } from './singletons/navigation';
import { homePage } from './singletons/homePage';
import { aboutPage } from './singletons/aboutPage';

/** All schema types to register with Sanity */
export const schemaTypes = [
  // Objects
  heroBlock,
  imageMosaicBlock,
  accordionBlock,
  cardGridBlock,
  youtubeEmbedBlock,
  // Documents
  person,
  sermon,
  event,
  ministry,
  page,
  // Singletons
  siteSettings,
  navigation,
  homePage,
  aboutPage,
];

/** Singleton type names — used by structure builder to filter from default list */
export const singletonTypes = new Set(['siteSettings', 'navigation', 'homePage', 'aboutPage']);

/** Singleton document IDs per language */
export const singletonDocIds = [
  { id: 'siteSettings-en', type: 'siteSettings', title: 'Site Settings (EN)' },
  { id: 'siteSettings-zh', type: 'siteSettings', title: 'Site Settings (ZH)' },
  { id: 'navigation-en', type: 'navigation', title: 'Navigation (EN)' },
  { id: 'navigation-zh', type: 'navigation', title: 'Navigation (ZH)' },
  { id: 'homePage-en', type: 'homePage', title: 'Home Page (EN)' },
  { id: 'homePage-zh', type: 'homePage', title: 'Home Page (ZH)' },
  { id: 'aboutPage-en', type: 'aboutPage', title: 'About Page (EN)' },
  { id: 'aboutPage-zh', type: 'aboutPage', title: 'About Page (ZH)' },
];

import { createClient } from '@sanity/client';

const projectId = import.meta.env.SANITY_PROJECT_ID || 'placeholder';
const dataset = import.meta.env.SANITY_DATASET || 'production';

export const client = createClient({
  projectId,
  dataset,
  apiVersion: '2026-03-31',
  useCdn: true,
});

export { projectId, dataset };

// ---------------------------------------------------------------------------
// Shared types — lightweight interfaces matching schema shapes.
// Full Sanity-generated types can replace these later.
// ---------------------------------------------------------------------------

export interface SanitySlug {
  _type: 'slug';
  current: string;
}

export interface PortableTextBlock {
  _type: string;
  _key: string;
  [key: string]: unknown;
}

export interface SanityImage {
  _type: 'image';
  asset: { _ref: string; _type: 'reference' };
}

export interface Page {
  _id: string;
  _type: 'page';
  title: string;
  slug: SanitySlug;
  body: PortableTextBlock[];
  language: 'en' | 'zh';
}

export interface Sermon {
  _id: string;
  _type: 'sermon';
  title: string;
  speaker?: string;
  date?: string;
  series?: string;
  scripture?: string;
  videoId?: string;
  language: 'en' | 'zh';
}

export interface Event {
  _id: string;
  _type: 'event';
  title: string;
  date?: string;
  endDate?: string;
  time?: string;
  location?: string;
  description?: PortableTextBlock[];
  recurring?: boolean;
  language: 'en' | 'zh';
}

export interface Ministry {
  _id: string;
  _type: 'ministry';
  name: string;
  description?: PortableTextBlock[];
  leader?: { _ref: string };
  meetingTime?: string;
  language: 'en' | 'zh';
}

export interface SocialLink {
  platform: string;
  url: string;
}

export interface SiteSettings {
  _id: string;
  _type: 'siteSettings';
  churchName: string;
  address?: string;
  phone?: string;
  email?: string;
  socialLinks?: SocialLink[];
  language: 'en' | 'zh';
}

export interface NavChild {
  label: string;
  href?: string;
}

export interface NavItem {
  label: string;
  href?: string;
  children?: NavChild[];
}

export interface Navigation {
  _id: string;
  _type: 'navigation';
  navItems: NavItem[];
  language: 'en' | 'zh';
}

export interface ServiceTime {
  label: string;
  time: string;
}

export interface Pillar {
  title: string;
  description?: string;
}

export interface NextStep {
  title: string;
  body?: string;
  href?: string;
  image?: SanityImage;
}

export interface MosaicImage extends SanityImage {
  alt?: string;
}

export interface HomePage {
  _id: string;
  _type: 'homePage';
  heroImage?: SanityImage;
  heroTitle: string;
  heroSubtitle?: string;
  heroCtaText?: string;
  heroCtaHref?: string;
  serviceTimes?: ServiceTime[];
  mosaicImages?: MosaicImage[];
  pillars?: Pillar[];
  nextSteps?: NextStep[];
  language: 'en' | 'zh';
}

export interface BeliefItem {
  _key: string;
  title: string;
  content?: PortableTextBlock[];
}

export interface AboutPage {
  _id: string;
  _type: 'aboutPage';
  whoWeAreHeading?: string;
  whoWeAreBody?: PortableTextBlock[];
  whoWeAreImage?: SanityImage;
  beliefs?: BeliefItem[];
  staffOrder?: { _ref: string }[];
  language: 'en' | 'zh';
}

export interface Person {
  _id: string;
  _type: 'person';
  name: string;
  role?: string;
  bio?: PortableTextBlock[];
  photo?: SanityImage;
  language: 'en' | 'zh';
}

// ---------------------------------------------------------------------------
// GROQ query helpers
// ---------------------------------------------------------------------------

type Language = 'en' | 'zh';

/**
 * Fetch a page by its slug and language.
 */
export async function getPageBySlug(
  slug: string,
  language: Language = 'en',
): Promise<Page | null> {
  return client.fetch<Page | null>(
    `*[_type == "page" && slug.current == $slug && language == $language][0]`,
    { slug, language },
  );
}

/**
 * Fetch all sermons for a language, newest first.
 */
export async function getSermons(language: Language = 'en'): Promise<Sermon[]> {
  return client.fetch<Sermon[]>(
    `*[_type == "sermon" && language == $language] | order(date desc)`,
    { language },
  );
}

/**
 * Fetch upcoming events for a language, soonest first.
 */
export async function getEvents(language: Language = 'en'): Promise<Event[]> {
  return client.fetch<Event[]>(
    `*[_type == "event" && language == $language] | order(date asc)`,
    { language },
  );
}

/**
 * Fetch all ministries for a language.
 */
export async function getMinistries(
  language: Language = 'en',
): Promise<Ministry[]> {
  return client.fetch<Ministry[]>(
    `*[_type == "ministry" && language == $language] | order(name asc)`,
    { language },
  );
}

/**
 * Fetch the singleton site-settings document for a language.
 * Singleton IDs follow the pattern `{type}-{lang}` per D-decision.
 */
export async function getSiteSettings(
  language: Language = 'en',
): Promise<SiteSettings | null> {
  return client.fetch<SiteSettings | null>(
    `*[_type == "siteSettings" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton navigation document for a language.
 */
export async function getNavigation(
  language: Language = 'en',
): Promise<Navigation | null> {
  return client.fetch<Navigation | null>(
    `*[_type == "navigation" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton home-page document for a language.
 */
export async function getHomePage(
  language: Language = 'en',
): Promise<HomePage | null> {
  return client.fetch<HomePage | null>(
    `*[_type == "homePage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton about-page document for a language.
 */
export async function getAboutPage(
  language: Language = 'en',
): Promise<AboutPage | null> {
  return client.fetch<AboutPage | null>(
    `*[_type == "aboutPage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch person documents for a language, ordered by name.
 */
export async function getStaff(
  language: Language = 'en',
): Promise<Person[]> {
  return client.fetch<Person[]>(
    `*[_type == "person" && language == $language] | order(name asc)`,
    { language },
  );
}

// ---------------------------------------------------------------------------
// Image helpers
// ---------------------------------------------------------------------------

/**
 * Resolve a Sanity image asset reference to a CDN URL.
 *
 * Asset refs look like `image-<id>-<WxH>-<ext>`. We strip the `image-`
 * prefix and replace the last `-` (before the extension) with `.` to get
 * the filename portion used in the CDN path.
 *
 * Example ref: `image-abc123-800x600-jpg`
 * Result:      `https://cdn.sanity.io/images/{projectId}/{dataset}/abc123-800x600.jpg`
 */
export function urlForImage(
  image: SanityImage | undefined | null,
  options?: { width?: number; format?: string },
): string {
  if (!image?.asset?._ref) return '';

  const ref = image.asset._ref;
  // Strip leading "image-" and split on the last "-" to get id and extension
  const withoutPrefix = ref.replace(/^image-/, '');
  const lastDash = withoutPrefix.lastIndexOf('-');
  if (lastDash === -1) return '';

  const idAndDimensions = withoutPrefix.slice(0, lastDash);
  const ext = withoutPrefix.slice(lastDash + 1);
  const filename = `${idAndDimensions}.${ext}`;

  let url = `https://cdn.sanity.io/images/${projectId}/${dataset}/${filename}`;

  const params = new URLSearchParams();
  if (options?.width) params.set('w', String(options.width));
  if (options?.format) params.set('fm', options.format);
  const qs = params.toString();
  if (qs) url += `?${qs}`;

  return url;
}

// ---------------------------------------------------------------------------
// Portable Text → HTML (lightweight server-side renderer)
// ---------------------------------------------------------------------------

/**
 * Convert an array of Portable Text blocks to an HTML string.
 *
 * Handles `block` type with `normal` style (paragraphs), `strong`/`em` marks,
 * and `link` annotations. Other block types are silently skipped.
 */
export function portableTextToHtml(blocks: PortableTextBlock[] | undefined | null): string {
  if (!blocks?.length) return '';

  return blocks
    .filter((b) => b._type === 'block')
    .map((block) => {
      const children = (block.children as Array<{
        _type: string;
        text: string;
        marks?: string[];
      }>) || [];

      const markDefs = (block.markDefs as Array<{
        _key: string;
        _type: string;
        href?: string;
      }>) || [];

      const inner = children
        .map((child) => {
          let text = escapeHtml(child.text || '');
          if (!child.marks?.length) return text;

          for (const mark of child.marks) {
            if (mark === 'strong') {
              text = `<strong>${text}</strong>`;
            } else if (mark === 'em') {
              text = `<em>${text}</em>`;
            } else {
              // Check markDefs for link annotations
              const def = markDefs.find((d) => d._key === mark);
              if (def?._type === 'link' && def.href) {
                text = `<a href="${escapeHtml(def.href)}">${text}</a>`;
              }
            }
          }
          return text;
        })
        .join('');

      return `<p>${inner}</p>`;
    })
    .join('\n');
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ---------------------------------------------------------------------------
// Visual Editing — draft-aware query helper for server-rendered preview
// ---------------------------------------------------------------------------

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';

/**
 * Draft-aware query helper for preview/visual-editing contexts.
 *
 * When `PUBLIC_SANITY_VISUAL_EDITING_ENABLED` is `'true'`:
 *   - Uses `perspective: 'previewDrafts'` so editors see unpublished changes
 *   - Injects `SANITY_API_READ_TOKEN` (server-only) for authenticated draft access
 *   - Enables stega encoding and result source maps for click-to-edit overlays
 *
 * When disabled, falls back to published perspective with no token or stega.
 *
 * This is a *parallel* helper — existing getPageBySlug / getSermons / etc.
 * remain unchanged for static build-time fetching.
 */
export async function loadQuery<T = unknown>(
  query: string,
  params: Record<string, unknown> = {},
): Promise<{ data: T }> {
  if (isVisualEditingEnabled) {
    const token = import.meta.env.SANITY_API_READ_TOKEN;
    if (!token) {
      throw new Error(
        '[sanity/loadQuery] PUBLIC_SANITY_VISUAL_EDITING_ENABLED is true but ' +
          'SANITY_API_READ_TOKEN is not set. Add the token to your environment ' +
          '(server-only, no PUBLIC_ prefix).',
      );
    }

    if (import.meta.env.DEV) {
      console.debug('[sanity/loadQuery] perspective: previewDrafts (visual editing enabled)');
    }

    const data = await client.fetch<T>(query, params, {
      perspective: 'previewDrafts',
      stega: true,
      token,
      resultSourceMap: true,
    });
    return { data };
  }

  const data = await client.fetch<T>(query, params, {
    perspective: 'published',
  });
  return { data };
}

